-- =====================================================================
-- SETUP DATABASE SUPABASE (PostgreSQL) - Sistem Kurikulum OBE
-- Digenerate dari model SQLAlchemy + data seeder aplikasi.
-- Tempel SELURUH isi file ini ke Supabase Dashboard > SQL Editor > Run.
-- =====================================================================
BEGIN;

-- 1) Bersihkan tabel lama (urutan terbalik, CASCADE)
DROP TABLE IF EXISTS "rps_minggu" CASCADE;
DROP TABLE IF EXISTS "teknik_penilaian" CASCADE;
DROP TABLE IF EXISTS "tahap_penilaian" CASCADE;
DROP TABLE IF EXISTS "sub_cpmk" CASCADE;
DROP TABLE IF EXISTS "nilai_mahasiswa" CASCADE;
DROP TABLE IF EXISTS "mapping_cpmk_mk" CASCADE;
DROP TABLE IF EXISTS "bobot_penilaian" CASCADE;
DROP TABLE IF EXISTS "rps" CASCADE;
DROP TABLE IF EXISTS "mapping_cpl_sndikti" CASCADE;
DROP TABLE IF EXISTS "mapping_cpl_pl" CASCADE;
DROP TABLE IF EXISTS "mapping_cpl_mk" CASCADE;
DROP TABLE IF EXISTS "mapping_cpl_bk" CASCADE;
DROP TABLE IF EXISTS "mapping_bk_mk" CASCADE;
DROP TABLE IF EXISTS "dokumen_bukti" CASCADE;
DROP TABLE IF EXISTS "cpmk" CASCADE;
DROP TABLE IF EXISTS "profil_lulusan" CASCADE;
DROP TABLE IF EXISTS "mata_kuliah" CASCADE;
DROP TABLE IF EXISTS "mahasiswa" CASCADE;
DROP TABLE IF EXISTS "log_peninjauan" CASCADE;
DROP TABLE IF EXISTS "cpl_sn_dikti" CASCADE;
DROP TABLE IF EXISTS "cpl_prodi" CASCADE;
DROP TABLE IF EXISTS "bahan_kajian" CASCADE;
DROP TABLE IF EXISTS "users" CASCADE;
DROP TABLE IF EXISTS "periode_kurikulum" CASCADE;
DROP TABLE IF EXISTS "program_studi" CASCADE;
DROP TABLE IF EXISTS "fakultas" CASCADE;
DROP TABLE IF EXISTS "universitas" CASCADE;
DROP TABLE IF EXISTS "kategori_pl" CASCADE;
DROP TABLE IF EXISTS "jenis_mk" CASCADE;

-- 2) Buat tabel (tipe Postgres: SERIAL/BOOLEAN/TIMESTAMP/TEXT, dll)
CREATE TABLE jenis_mk (
	nama VARCHAR(100) NOT NULL, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id)
);

CREATE TABLE kategori_pl (
	nama VARCHAR(150) NOT NULL, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id)
);

CREATE TABLE universitas (
	nama VARCHAR(200) NOT NULL, 
	alamat TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id)
);

CREATE TABLE fakultas (
	universitas_id INTEGER NOT NULL, 
	nama VARCHAR(200) NOT NULL, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(universitas_id) REFERENCES universitas (id)
);

CREATE TABLE program_studi (
	fakultas_id INTEGER NOT NULL, 
	nama VARCHAR(200) NOT NULL, 
	jenjang VARCHAR(20), 
	akreditasi VARCHAR(50), 
	visi TEXT, 
	misi TEXT, 
	website VARCHAR(200), 
	email VARCHAR(200), 
	gelar_lulusan VARCHAR(50), 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(fakultas_id) REFERENCES fakultas (id)
);

CREATE TABLE periode_kurikulum (
	prodi_id INTEGER NOT NULL, 
	nama VARCHAR(100) NOT NULL, 
	tahun_mulai INTEGER NOT NULL, 
	tahun_selesai INTEGER NOT NULL, 
	status VARCHAR(20), 
	locked BOOLEAN, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(prodi_id) REFERENCES program_studi (id)
);

CREATE TABLE users (
	username VARCHAR(100) NOT NULL, 
	password_hash VARCHAR(255) NOT NULL, 
	nama VARCHAR(200) NOT NULL, 
	email VARCHAR(200), 
	role VARCHAR(50) NOT NULL, 
	prodi_id INTEGER, 
	fakultas_id INTEGER, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (username), 
	FOREIGN KEY(prodi_id) REFERENCES program_studi (id), 
	FOREIGN KEY(fakultas_id) REFERENCES fakultas (id)
);

CREATE TABLE bahan_kajian (
	periode_id INTEGER NOT NULL, 
	kode VARCHAR(10) NOT NULL, 
	nama VARCHAR(200) NOT NULL, 
	deskripsi TEXT, 
	kompetensi VARCHAR(20), 
	referensi TEXT, 
	ref_buku TEXT, 
	ref_spreadsheet TEXT, 
	ref_pikobe TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(periode_id) REFERENCES periode_kurikulum (id)
);

CREATE TABLE cpl_prodi (
	periode_id INTEGER NOT NULL, 
	kode VARCHAR(10) NOT NULL, 
	deskripsi TEXT NOT NULL, 
	referensi TEXT, 
	ref_buku TEXT, 
	ref_spreadsheet TEXT, 
	ref_pikobe TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(periode_id) REFERENCES periode_kurikulum (id)
);

CREATE TABLE cpl_sn_dikti (
	periode_id INTEGER NOT NULL, 
	kode VARCHAR(20) NOT NULL, 
	kategori VARCHAR(10) NOT NULL, 
	deskripsi TEXT NOT NULL, 
	referensi TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(periode_id) REFERENCES periode_kurikulum (id)
);

CREATE TABLE log_peninjauan (
	jenis VARCHAR(40) NOT NULL, 
	periode_id INTEGER, 
	judul VARCHAR(300) NOT NULL, 
	tanggal DATE NOT NULL, 
	lokasi VARCHAR(200), 
	peserta TEXT, 
	catatan TEXT, 
	status VARCHAR(50), 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(periode_id) REFERENCES periode_kurikulum (id)
);

CREATE TABLE mahasiswa (
	user_id INTEGER, 
	nim VARCHAR(20) NOT NULL, 
	nama VARCHAR(200) NOT NULL, 
	angkatan INTEGER NOT NULL, 
	prodi_id INTEGER NOT NULL, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	UNIQUE (nim), 
	FOREIGN KEY(prodi_id) REFERENCES program_studi (id)
);

CREATE TABLE mata_kuliah (
	periode_id INTEGER NOT NULL, 
	kode VARCHAR(10) NOT NULL, 
	nama VARCHAR(200) NOT NULL, 
	sks INTEGER NOT NULL, 
	semester INTEGER NOT NULL, 
	jenis VARCHAR(20), 
	is_capstone BOOLEAN, 
	prasyarat TEXT, 
	deskripsi_singkat TEXT, 
	referensi TEXT, 
	ref_buku TEXT, 
	ref_spreadsheet TEXT, 
	ref_pikobe TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(periode_id) REFERENCES periode_kurikulum (id)
);

CREATE TABLE profil_lulusan (
	periode_id INTEGER NOT NULL, 
	kode VARCHAR(10) NOT NULL, 
	deskripsi TEXT NOT NULL, 
	kategori VARCHAR(50), 
	referensi TEXT, 
	ref_buku TEXT, 
	ref_spreadsheet TEXT, 
	ref_pikobe TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(periode_id) REFERENCES periode_kurikulum (id)
);

CREATE TABLE cpmk (
	cpl_id INTEGER NOT NULL, 
	kode VARCHAR(20) NOT NULL, 
	deskripsi TEXT NOT NULL, 
	referensi TEXT, 
	ref_buku TEXT, 
	ref_spreadsheet TEXT, 
	ref_pikobe TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpl_id) REFERENCES cpl_prodi (id)
);

CREATE TABLE dokumen_bukti (
	log_id INTEGER NOT NULL, 
	filename VARCHAR(300) NOT NULL, 
	filepath VARCHAR(500), 
	storage_key VARCHAR(500), 
	storage_backend VARCHAR(20), 
	tipe VARCHAR(50), 
	ukuran INTEGER, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(log_id) REFERENCES log_peninjauan (id)
);

CREATE TABLE mapping_bk_mk (
	id SERIAL NOT NULL, 
	bk_id INTEGER NOT NULL, 
	mk_id INTEGER NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(bk_id) REFERENCES bahan_kajian (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id)
);

CREATE TABLE mapping_cpl_bk (
	id SERIAL NOT NULL, 
	cpl_id INTEGER NOT NULL, 
	bk_id INTEGER NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpl_id) REFERENCES cpl_prodi (id), 
	FOREIGN KEY(bk_id) REFERENCES bahan_kajian (id)
);

CREATE TABLE mapping_cpl_mk (
	id SERIAL NOT NULL, 
	cpl_id INTEGER NOT NULL, 
	mk_id INTEGER NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpl_id) REFERENCES cpl_prodi (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id)
);

CREATE TABLE mapping_cpl_pl (
	id SERIAL NOT NULL, 
	cpl_id INTEGER NOT NULL, 
	pl_id INTEGER NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpl_id) REFERENCES cpl_prodi (id), 
	FOREIGN KEY(pl_id) REFERENCES profil_lulusan (id)
);

CREATE TABLE mapping_cpl_sndikti (
	id SERIAL NOT NULL, 
	cpl_prodi_id INTEGER NOT NULL, 
	cpl_sn_id INTEGER NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpl_prodi_id) REFERENCES cpl_prodi (id), 
	FOREIGN KEY(cpl_sn_id) REFERENCES cpl_sn_dikti (id)
);

CREATE TABLE rps (
	mk_id INTEGER NOT NULL, 
	periode_id INTEGER NOT NULL, 
	kode_dokumen VARCHAR(50), 
	deskripsi_singkat TEXT, 
	pustaka_utama TEXT, 
	pustaka_pendukung TEXT, 
	dosen_pengampu TEXT, 
	dosen_koordinator VARCHAR(200), 
	tanggal_penyusunan VARCHAR(20), 
	bobot_teori_sks INTEGER, 
	bobot_praktikum_sks INTEGER, 
	media_software TEXT, 
	media_hardware TEXT, 
	mk_prasyarat TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id), 
	FOREIGN KEY(periode_id) REFERENCES periode_kurikulum (id)
);

CREATE TABLE bobot_penilaian (
	cpl_id INTEGER NOT NULL, 
	mk_id INTEGER NOT NULL, 
	cpmk_id INTEGER NOT NULL, 
	partisipasi_pct INTEGER, 
	observasi_pct INTEGER, 
	unjuk_kerja_pct INTEGER, 
	uts_pct INTEGER, 
	uas_pct INTEGER, 
	tes_lisan_pct INTEGER, 
	total INTEGER, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpl_id) REFERENCES cpl_prodi (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id), 
	FOREIGN KEY(cpmk_id) REFERENCES cpmk (id)
);

CREATE TABLE mapping_cpmk_mk (
	id SERIAL NOT NULL, 
	cpmk_id INTEGER NOT NULL, 
	mk_id INTEGER NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpmk_id) REFERENCES cpmk (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id)
);

CREATE TABLE nilai_mahasiswa (
	mahasiswa_id INTEGER NOT NULL, 
	mk_id INTEGER NOT NULL, 
	cpmk_id INTEGER NOT NULL, 
	semester_aktif VARCHAR(20), 
	skor_partisipasi FLOAT, 
	skor_observasi FLOAT, 
	skor_unjuk_kerja FLOAT, 
	skor_uts FLOAT, 
	skor_uas FLOAT, 
	skor_tes_lisan FLOAT, 
	skor_total FLOAT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(mahasiswa_id) REFERENCES mahasiswa (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id), 
	FOREIGN KEY(cpmk_id) REFERENCES cpmk (id)
);

CREATE TABLE sub_cpmk (
	cpmk_id INTEGER NOT NULL, 
	mk_id INTEGER NOT NULL, 
	kode VARCHAR(30) NOT NULL, 
	deskripsi TEXT NOT NULL, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpmk_id) REFERENCES cpmk (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id)
);

CREATE TABLE tahap_penilaian (
	cpl_id INTEGER NOT NULL, 
	mk_id INTEGER NOT NULL, 
	cpmk_id INTEGER NOT NULL, 
	tahap VARCHAR(30), 
	teknik_penilaian_text TEXT, 
	instrumen TEXT, 
	kriteria TEXT, 
	bobot INTEGER NOT NULL, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpl_id) REFERENCES cpl_prodi (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id), 
	FOREIGN KEY(cpmk_id) REFERENCES cpmk (id)
);

CREATE TABLE teknik_penilaian (
	cpl_id INTEGER NOT NULL, 
	mk_id INTEGER NOT NULL, 
	cpmk_id INTEGER NOT NULL, 
	partisipasi BOOLEAN, 
	observasi BOOLEAN, 
	unjuk_kerja BOOLEAN, 
	tes_tulis_uts BOOLEAN, 
	tes_tulis_uas BOOLEAN, 
	tes_lisan BOOLEAN, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(cpl_id) REFERENCES cpl_prodi (id), 
	FOREIGN KEY(mk_id) REFERENCES mata_kuliah (id), 
	FOREIGN KEY(cpmk_id) REFERENCES cpmk (id)
);

CREATE TABLE rps_minggu (
	rps_id INTEGER NOT NULL, 
	minggu_ke INTEGER NOT NULL, 
	sub_cpmk_id INTEGER, 
	bentuk_pembelajaran TEXT, 
	metode_luring TEXT, 
	metode_daring TEXT, 
	materi TEXT, 
	bobot_penilaian_persen FLOAT, 
	indikator TEXT, 
	kriteria_teknik TEXT, 
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(rps_id) REFERENCES rps (id), 
	FOREIGN KEY(sub_cpmk_id) REFERENCES sub_cpmk (id)
);

