INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL01', 'Mampu memahami, menganalisis, dan menilai konsep dasar dan peran sistem informasi dalam mengelola data dan memberikan rekomendasi pengambilan keputusan pada proses dan sistem organisasi', NULL, 1, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL02', 'Mampu merancang dan menggunakan database, serta mengolah dan menganalisa data dengan alat dan teknik pengolahan data', NULL, 2, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL03', 'Mampu memahami dan menggunakan berbagai metodologi pengembangan sistem beserta alat pemodelan sistem dan menganalisa kebutuhan pengguna dalam membangun sistem informasi untuk mencapai tujuan organisasi', NULL, 3, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL04', 'Mampu membuat perencanaan infrastruktur TI, arsitektur jaringan, layanan fisik dan cloud, menganalisa konsep identifikasi, otentikasi, otorisasi akses dalam konteks melindungi orang dan perangkat', NULL, 4, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL05', 'Mampu memahami dan menerapkan kode etik dalam penggunaan informasi dan data pada perancangan, implementasi, dan penggunaan suatu sistem', NULL, 5, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL06', 'Memiliki kemampuan merencanakan, menerapkan, memelihara dan meningkatkan sistem informasi organisasi untuk mencapai tujuan dan sasaran organisasi yang strategis baik jangka pendek maupun jangka panjang', NULL, 6, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL07', 'Mampu memahami, mengidentifikasi dan menerapkan konsep, teknik dan metodologi manajemen proyek sistem informasi', NULL, 7, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL08', 'Mampu memahami dan menerapkan konsep, metode, teknik, dan tahapan data mining serta visualisasi data dalam pengolahan data, pengorganisasian data, dan penyajian informasi yang efektif, efisien, dan estetik', NULL, 8, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL09', 'Mampu memahami dan menerapkan model sistem, metode dan berbagai teknik peningkatan bisnis proses, peluang inovasi digital dalam pengelolaan bisnis yang memanfaatkan teknologi', NULL, 9, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL10', 'Mampu menunjukkan sikap profesionalitas, integritas, dan berjati diri islami yang dilengkapi dengan kemampuan komunikasi, kepemimpinan, bekerja sama dan bertanggung jawab atas pekerjaan di bidang keahliannya', NULL, 10, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL11', 'Mampu menunjukkan sikap taat hukum, disiplin, dan menghargai keanekaragaman melalui internalisasi nilai, norma, etika akademik, semangat kemandirian, kejuangan, dan kewirausahaan', NULL, 11, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL12', 'Mampu menunjukkan kinerja mandiri, bermutu, terukur, berfikir logis, kritis, sistematis, dan inovatif, komunikatif dalam mengembangkan ilmu pengetahuan yang memperhatikan nilai humaniora sesuai bidang keahliannya', NULL, 12, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL13', 'Mampu mengkaji implikasi pengembangan ilmu pengetahuan dengan menerapkan keahliannya dalam rangka menghasilkan solusi, menyusun deskripsi saintifik hasil kajian dalam bentuk laporan ilmiah yang sahih dan original', NULL, 13, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
INSERT INTO "cpl_prodi" ("periode_id", "kode", "deskripsi", "referensi", "id", "created_at", "updated_at") VALUES (1, 'CPL14', 'Mampu melakukan evaluasi diri dan supervisi terhadap penyelesaian pekerjaan sebagai wujud tanggung jawab atas pencapaian hasil kelompok kerja', NULL, 14, '2026-06-20T13:18:42.097542', '2026-06-20T13:18:42.097542');
