INSERT INTO "profil_lulusan" ("periode_id", "kode", "deskripsi", "kategori", "referensi", "id", "created_at", "updated_at") VALUES (1, 'PL1', 'Lulusan memiliki kemampuan untuk merencanakan, menganalisis, merancang, membangun, mengujicoba, menerapkan, dan mengevaluasi sistem informasi dalam sebuah proyek yang selaras dengan tujuan organisasi', 'Penciri Utama', NULL, 1, '2026-06-20T13:18:42.095789', '2026-06-20T13:18:42.095789');
INSERT INTO "profil_lulusan" ("periode_id", "kode", "deskripsi", "kategori", "referensi", "id", "created_at", "updated_at") VALUES (1, 'PL2', 'Lulusan memiliki kemampuan memahami, menerapkan, dan mengintegrasikan model bisnis dengan menggunakan metode dan berbagai teknik peningkatan bisnis proses yang mendatangkan suatu nilai tambah bagi organisasi', 'Penciri Utama', NULL, 2, '2026-06-20T13:18:42.095789', '2026-06-20T13:18:42.095789');
INSERT INTO "profil_lulusan" ("periode_id", "kode", "deskripsi", "kategori", "referensi", "id", "created_at", "updated_at") VALUES (1, 'PL3', 'Lulusan memiliki kemampuan untuk mengolah, menganalisis, dan menyajikan data yang dikembangkan dengan konsep big data dan business intelligence untuk membantu dalam proses pengambilan keputusan', 'Tambahan KK dan P', NULL, 3, '2026-06-20T13:18:42.095789', '2026-06-20T13:18:42.095789');
INSERT INTO "profil_lulusan" ("periode_id", "kode", "deskripsi", "kategori", "referensi", "id", "created_at", "updated_at") VALUES (1, 'PL4', 'Lulusan memiliki sikap religius, beretika, dan peka terhadap lingkungan sosial sebagai seorang warga negara dengan berlandaskan nilai ahlussunah waljamaah (Aswaja)', 'Sikap', NULL, 4, '2026-06-20T13:18:42.095789', '2026-06-20T13:18:42.095789');
INSERT INTO "profil_lulusan" ("periode_id", "kode", "deskripsi", "kategori", "referensi", "id", "created_at", "updated_at") VALUES (1, 'PL5', 'Lulusan memiliki kemampuan berpikir kritis dan inovatif, bekerja mandiri, membuat keputusan tepat, mendokumentasikan data dengan benar, menyusun karya ilmiah, berkomunikasi efektif', 'Keterampilan Umum dan Sikap', NULL, 5, '2026-06-20T13:18:42.095789', '2026-06-20T13:18:42.095789');
